patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index de3b981a4fe3..5bdbb6acdf72 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7304,6 +7304,17 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
   auto Iter = vp_depth_first_deep(Plan.getVectorLoopRegion()->getEntry());
   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(Iter)) {
     for (VPRecipeBase &R : *VPBB) {
+      if (auto *Recipe = dyn_cast<VPSingleDefRecipe>(&R)) {
+        if (auto *I = dyn_cast_or_null<Instruction>(Recipe->getUnderlyingValue())) {
+          if (I->getOpcode() == Instruction::Shl &&
+              !isa<Constant>(I->getOperand(1))) {
+            // The VPlan-native path can vectorize shifts with a variable shift
+            // amount, which is not supported by the legacy path.
+            return true;
+          }
+        }
+      }
+
       if (auto *IR = dyn_cast<VPInterleaveRecipe>(&R)) {
         auto *IG = IR->getInterleaveGroup();
         unsigned NumMembers = IG->getNumMembers();

